class Solution:
  def sort(self, nums: list[int]) -> list[int]:
      if len(nums) <= 1:
        return nums;
      RADIX = 10
      placement = 1
      max_digit = max(nums);
      while placement < max_digit:
        placement *= RADIX;
      buck = [list() for _ in range(RADIX)];
      for i in nums:
        tmp = int((i / placement) % RADIX)
        buck[tmp].append(i);
      nums = []; 
      for b in buck:
        nums = nums + b;
      for i in range(len(nums) - 1):
        for j in range(len(nums) - 1 - i):
          if nums[j] > nums[j + 1]:
            nums[j], nums[j + 1] = nums[j + 1], nums[j];
      return nums;

