class Solution {
  public:
    vector<int> sort(vector<int>& nums) {
      if (nums.size() <= 1) return nums;
      int RADIX = 10;
      int placement = 1;
      int max_digit = max_element(nums.begin(), nums.end()) - nums.begin();
      while (placement < max_digit) placement *= RADIX;
      vector<vector<int>> buck(RADIX);
      for (int i : nums) {
        int tmp = int((i / placement) % RADIX);
        buck[tmp].push_back(i);
      }
      for (vector<int>& b : buck) {
        for (int i = 0; i < b.size() - 1; i++) {
          for (int j = 0; j < b.size() - 1 - i; j++) {
            if (b[j] > b[j + 1]) {
              swap(b[j], b[j + 1]);
            }
          }
        }
      }
      vector<int> sorted_nums;
      for (vector<int>& b : buck) {
        sorted_nums.insert(sorted_nums.end(), b.begin(), b.end());
      }
      return sorted_nums;
    }
};
